import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import { Modal, Button, Form } from "react-bootstrap";
import Pagination from "../components/Pagination";

// Usamos la variable de entorno para facilitar el despliegue
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function ClientesPage() {
  const [clientes, setClientes] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [mostrarModal, setMostrarModal] = useState(false);
  const [editando, setEditando] = useState(null);
  const [nuevoCliente, setNuevoCliente] = useState({
    Nombre: "",
    Apellido: "",
    Telefono: "",
    Correo: "",
  });

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 5;

  useEffect(() => {
    obtenerClientes();
  }, []);

  const obtenerClientes = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/clientes`);
      // PostgreSQL suele devolver los campos según se definieron. 
      // Si tu backend usa alias, esto funcionará directo.
      setClientes(res.data);
    } catch (err) {
      console.error("❌ Error al obtener clientes:", err);
    }
  };

  const manejarCambio = (e) => {
    setNuevoCliente({ ...nuevoCliente, [e.target.name]: e.target.value });
  };

  const abrirModal = (cliente = null) => {
    if (cliente) {
      // Soportamos tanto ClienteID como id (Postgres)
      const id = cliente.ClienteID || cliente.id;
      setEditando(id);
      setNuevoCliente({
        Nombre: cliente.Nombre || cliente.nombre,
        Apellido: cliente.Apellido || cliente.apellido,
        Telefono: cliente.Telefono || cliente.telefono || "",
        Correo: cliente.Correo || cliente.correo || "",
      });
    } else {
      setEditando(null);
      setNuevoCliente({ Nombre: "", Apellido: "", Telefono: "", Correo: "" });
    }
    setMostrarModal(true);
  };

  const cerrarModal = () => setMostrarModal(false);

  const guardarCliente = async (e) => {
    e.preventDefault();
    try {
      if (editando) {
        await axios.put(`${API_URL}/api/clientes/${editando}`, nuevoCliente);
      } else {
        await axios.post(`${API_URL}/api/clientes`, nuevoCliente);
      }
      cerrarModal();
      obtenerClientes();
    } catch (err) {
      console.error("❌ Error al guardar cliente:", err);
      alert("No se pudo guardar el cliente. Verifica la conexión.");
    }
  };

  const eliminarCliente = async (id) => {
    if (!window.confirm("¿Seguro que deseas eliminar este cliente?")) return;
    try {
      await axios.delete(`${API_URL}/api/clientes/${id}`);
      obtenerClientes();
    } catch (err) {
      console.error("❌ Error al eliminar cliente:", err);
    }
  };

  // Filtrado de búsqueda (con soporte para minúsculas de Postgres)
  const clientesFiltrados = clientes.filter((c) => {
    const nombre = (c.Nombre || c.nombre || "").toLowerCase();
    const apellido = (c.Apellido || c.apellido || "").toLowerCase();
    const correo = (c.Correo || c.correo || "").toLowerCase();
    const term = busqueda.toLowerCase();
    return nombre.includes(term) || apellido.includes(term) || correo.includes(term);
  });

  // Lógica de Paginación
  const indexLast = currentPage * itemsPerPage;
  const indexFirst = indexLast - itemsPerPage;
  const currentItems = clientesFiltrados.slice(indexFirst, indexLast);

  return (
    <div className="container mt-4">
      <div className="card shadow-sm p-4">
        <h2 className="text-primary mb-4 fw-bold">👥 Gestión de Clientes</h2>
        
        <div className="d-flex justify-content-between mb-3 gap-3">
          <input
            type="text"
            className="form-control"
            placeholder="Buscar por nombre, apellido o correo..."
            value={busqueda}
            onChange={(e) => { setBusqueda(e.target.value); setCurrentPage(1); }}
          />
          <button className="btn btn-success d-flex align-items-center" onClick={() => abrirModal()}>
            <span className="me-1">➕</span> Nuevo
          </button>
        </div>

        <div className="table-responsive">
          <table className="table table-hover align-middle">
            <thead className="table-dark">
              <tr className="text-center">
                <th>ID</th>
                <th>Nombre Completo</th>
                <th>Teléfono</th>
                <th>Correo</th>
                <th>Registro</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {currentItems.length > 0 ? (
                currentItems.map((c) => (
                  <tr key={c.ClienteID || c.id} className="text-center">
                    <td>{c.ClienteID || c.id}</td>
                    <td className="fw-bold">{`${c.Nombre || c.nombre} ${c.Apellido || c.apellido}`}</td>
                    <td>{c.Telefono || c.telefono || "—"}</td>
                    <td>{c.Correo || c.correo || "—"}</td>
                    <td>
                      {c.FechaRegistro || c.fecharegistro
                        ? new Date(c.FechaRegistro || c.fecharegistro).toLocaleDateString()
                        : "—"}
                    </td>
                    <td>
                      <button onClick={() => abrirModal(c)} className="btn btn-outline-warning btn-sm me-2">
                        ✏️
                      </button>
                      <button onClick={() => eliminarCliente(c.ClienteID || c.id)} className="btn btn-outline-danger btn-sm">
                        🗑️
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="6" className="py-4 text-muted">No se encontraron clientes.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        <Pagination
          totalItems={clientesFiltrados.length}
          itemsPerPage={itemsPerPage}
          currentPage={currentPage}
          onPageChange={setCurrentPage}
        />
      </div>

      {/* Modal */}
      <Modal show={mostrarModal} onHide={cerrarModal} centered shadow>
        <Modal.Header closeButton className={editando ? "bg-warning text-dark" : "bg-success text-white"}>
          <Modal.Title className="fw-bold">
            {editando ? "✏️ Editar Cliente" : "➕ Nuevo Cliente"}
          </Modal.Title>
        </Modal.Header>
        <Form onSubmit={guardarCliente}>
          <Modal.Body className="p-4">
            <div className="row">
              <Form.Group className="col-md-6 mb-3">
                <Form.Label className="fw-bold">Nombre</Form.Label>
                <Form.Control type="text" name="Nombre" value={nuevoCliente.Nombre} onChange={manejarCambio} required placeholder="Ej. Juan" />
              </Form.Group>
              <Form.Group className="col-md-6 mb-3">
                <Form.Label className="fw-bold">Apellido</Form.Label>
                <Form.Control type="text" name="Apellido" value={nuevoCliente.Apellido} onChange={manejarCambio} required placeholder="Ej. Pérez" />
              </Form.Group>
            </div>
            <Form.Group className="mb-3">
              <Form.Label className="fw-bold">Teléfono</Form.Label>
              <Form.Control type="text" name="Telefono" value={nuevoCliente.Telefono} onChange={manejarCambio} placeholder="Ej. +503 1234-5678" />
            </Form.Group>
            <Form.Group className="mb-3">
              <Form.Label className="fw-bold">Correo Electrónico</Form.Label>
              <Form.Control type="email" name="Correo" value={nuevoCliente.Correo} onChange={manejarCambio} placeholder="correo@ejemplo.com" />
            </Form.Group>
          </Modal.Body>
          <Modal.Footer className="bg-light">
            <Button variant="secondary" onClick={cerrarModal}>Cancelar</Button>
            <Button type="submit" variant={editando ? "warning" : "success"}>
              {editando ? "Actualizar Cliente" : "Registrar Cliente"}
            </Button>
          </Modal.Footer>
        </Form>
      </Modal>
    </div>
  );
}
